css:
/* =====================================================
   LUFFY DARKEN ULTIMATE - 500+ LINES OF PERFECTION
   Background shows EVERYWHERE + Blue accents + Glass effect
   ===================================================== */

:root {
  --luffy-blue: #3a86ff;
  --luffy-blue-dark: #0050b3;
  --luffy-bg-dark: #0E0E0F;
  --luffy-glass: rgba(14, 14, 15, 0.82);
  --luffy-glass-light: rgba(14, 14, 15, 0.88);
  --luffy-text: #dbdee1;
  --luffy-text-secondary: #b5bac1;
  --luffy-mention: #FFB800;
}

/* ========== 1. GLOBAL ROOT BACKGROUND (CRITICAL) ========== */
html, body, #app-mount, .appMount-3, .app-2rEoOp {
  background-color: var(--luffy-bg-dark) !important;
  background-image: url('https://raw.githubusercontent.com/a67680293-sys/Revenge-theme/main/66ff8b8e6fe1d286aa44bab423133458.jpg') !important;
  background-size: cover !important;
  background-position: center center !important;
  background-attachment: fixed !important;
  background-repeat: no-repeat !important;
  background-blend-mode: multiply;
}

/* ========== 2. TRANSPARENT OVERLAYS FOR BG VISIBILITY ========== */
.layers-3iHuyZ, .layerContainer-2vKkMZ, .theme-dark {
  background-color: transparent !important;
}

/* ========== 3. GUILD SIDEBAR (left side) ========== */
[class*="guilds"], [class*="guildList"], [class*="guildListItem"],
.guilds-1SWlCJ, .guildListItem-3SmSlK {
  background-color: var(--luffy-glass) !important;
  backdrop-filter: blur(8px);
}

/* ========== 4. CHANNEL LIST (left-middle) ========== */
[class*="channels"], [class*="channelList"], [class*="privateChannels"],
.channels-1sY5ga, .privateChannels-oVCQqj, .container-1giJPf {
  background-color: var(--luffy-glass) !important;
  backdrop-filter: blur(8px);
}

/* ========== 5. MEMBER LIST (right side) ========== */
[class*="members"], [class*="memberList"], [class*="memberListSection"],
.members-1998pB, .container-1giJPf {
  background-color: var(--luffy-glass) !important;
  backdrop-filter: blur(8px);
}

/* ========== 6. CHAT AREA (center - MUST BE TRANSPARENT) ========== */
[class*="chat"], [class*="messages"], [class*="messagesWrapper"],
[class*="scroller"], [class*="messageList"], [class*="scrollerInner"],
.chat-1bRaxu, .messagesWrapper-1mRqco, .scroller-2TZvBN {
  background-color: transparent !important;
  background-image: none !important;
}

/* ========== 7. MESSAGE CONTAINERS (semi-transparent glass) ========== */
[class*="message"], [class*="messageGroup"], [class*="messageContent"],
.message-2QY9dM, .messageContent-2qWWxC {
  background-color: rgba(14, 14, 15, 0.15) !important;
  border-radius: 8px;
  margin: 2px 0;
}

[class*="message"]:hover {
  background-color: rgba(58, 134, 255, 0.12) !important;
}

/* ========== 8. HEADER / TITLE BAR ========== */
[class*="header"], [class*="titleBar"], [class*="headerBar"],
.header-1XpmZs, .titleBar-ac7pgm {
  background-color: var(--luffy-glass) !important;
  backdrop-filter: blur(8px);
  border-bottom: 1px solid rgba(58, 134, 255, 0.2);
}

/* ========== 9. MODALS & POPOUTS (glass with blue border) ========== */
[class*="modal"], [class*="popout"], [class*="tooltip"],
[class*="userPopout"], [class*="menu"], [class*="dropdown"],
.modal-yWgWj-, .popout-VsKjZd, .tooltip-2QfLtc {
  background-color: var(--luffy-glass-light) !important;
  backdrop-filter: blur(10px);
  border: 1px solid rgba(58, 134, 255, 0.35);
  border-radius: 12px;
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.3);
}

/* ========== 10. INPUT FIELDS & TEXTAREAS ========== */
input, textarea, select,
[class*="input"], [class*="textArea"], [class*="field"],
[class*="channelTextArea"], [class*="slateContainer"] {
  background-color: var(--luffy-glass) !important;
  color: var(--luffy-text) !important;
  border: 1px solid rgba(58, 134, 255, 0.4) !important;
  border-radius: 8px;
  transition: all 0.2s ease;
}

input:focus, textarea:focus, select:focus {
  border-color: var(--luffy-blue) !important;
  box-shadow: 0 0 8px rgba(58, 134, 255, 0.3) !important;
  background-color: rgba(14, 14, 15, 0.95) !important;
}

/* ========== 11. BUTTONS - PRIMARY (solid blue) ========== */
[class*="buttonPrimary"], [class*="lookFilled"][class*="colorBrand"],
[class*="brand"], [class*="positive"],
.button-1ZD-K6[class*="primary"] {
  background-color: var(--luffy-blue) !important;
  border-color: var(--luffy-blue) !important;
  color: #FFFFFF !important;
  transition: all 0.2s ease;
}

[class*="buttonPrimary"]:hover, [class*="lookFilled"][class*="colorBrand"]:hover {
  background-color: var(--luffy-blue-dark) !important;
  box-shadow: 0 4px 12px rgba(58, 134, 255, 0.4);
}

/* ========== 12. BUTTONS - SECONDARY (outline blue) ========== */
[class*="buttonSecondary"], [class*="lookOutlined"][class*="colorBrand"],
[class*="outline"],
.button-1ZD-K6[class*="secondary"] {
  background-color: rgba(14, 14, 15, 0.6) !important;
  border-color: var(--luffy-blue) !important;
  color: var(--luffy-blue) !important;
  transition: all 0.2s ease;
}

[class*="buttonSecondary"]:hover, [class*="lookOutlined"][class*="colorBrand"]:hover {
  background-color: rgba(58, 134, 255, 0.2) !important;
  box-shadow: 0 4px 12px rgba(58, 134, 255, 0.3);
}

/* ========== 13. BUTTONS - DANGER (red) ========== */
[class*="buttonDanger"], [class*="lookFilled"][class*="colorDanger"],
[class*="danger"],
.button-1ZD-K6[class*="danger"] {
  background-color: #f83838 !important;
  border-color: #f83838 !important;
  color: #FFFFFF !important;
}

[class*="buttonDanger"]:hover {
  background-color: #e02929 !important;
}

/* ========== 14. MENTIONS & PINGS (gold gradient) ========== */
.mention, .mention.interactive, [class*="mention"],
.mention-3XBnnM {
  background: linear-gradient(135deg, rgba(255, 184, 0, 0.9), rgba(255, 100, 0, 0.7)) !important;
  color: #FFFFFF !important;
  border-radius: 6px;
  box-shadow: 0 0 12px rgba(255, 184, 0, 0.5);
  font-weight: 700;
  padding: 2px 6px;
  transition: all 0.2s ease;
}

.mention:hover {
  background: linear-gradient(135deg, rgba(255, 184, 0, 1), rgba(255, 100, 0, 0.85)) !important;
  box-shadow: 0 0 16px rgba(255, 184, 0, 0.7);
}

/* ========== 15. TEXT COLORS ========== */
span, div, p, h1, h2, h3, h4, h5, h6,
[class*="text"], [class*="message"], [class*="channel"],
[class*="username"], [class*="name"], [class*="title"] {
  color: var(--luffy-text) !important;
}

[class*="secondary"], [class*="muted"], [class*="placeholder"] {
  color: var(--luffy-text-secondary) !important;
}

/* ========== 16. LINKS ========== */
a, [class*="link"], [class*="anchor"], [class*="textLink"],
.link-1Gc1jf {
  color: var(--luffy-blue) !important;
  text-decoration: none !important;
  transition: color 0.2s ease;
}

a:hover, [class*="link"]:hover {
  color: #7cb5ff !important;
  text-decoration: underline !important;
}

/* ========== 17. CHANNEL NAMES & ICONS ========== */
[class*="channelName"], [class*="categoryName"],
[class*="nameDefaultText"], [class*="channelIcon"],
[class*="hash"], [class*="prefix"],
.channelName-1QajIX, .icon-2W8DHg {
  color: var(--luffy-blue) !important;
}

[class*="channelName"]:hover, [class*="categoryName"]:hover {
  color: #7cb5ff !important;
}

/* ========== 18. SCROLLBARS (webkit + firefox) ========== */
* {
  scrollbar-width: thin;
  scrollbar-color: rgba(58, 134, 255, 0.65) rgba(14, 14, 15, 0.6);
}

::-webkit-scrollbar {
  width: 10px;
  height: 10px;
}

::-webkit-scrollbar-thumb {
  background: rgba(58, 134, 255, 0.65) !important;
  border-radius: 10px;
  border: 2px solid rgba(14, 14, 15, 0.6);
}

::-webkit-scrollbar-track {
  background: rgba(14, 14, 15, 0.6) !important;
}

::-webkit-scrollbar-corner {
  background: rgba(14, 14, 15, 0.6) !important;
}

/* ========== 19. STATUS INDICATORS ========== */
[class*="statusOnline"], [class*="statusStreaming"],
.status-1fhblQ[class*="online"] {
  background-color: var(--luffy-blue) !important;
}

[class*="statusIdle"], .status-1fhblQ[class*="idle"] {
  background-color: #faeb64 !important;
}

[class*="statusDND"], [class*="statusDo"], .status-1fhblQ[class*="dnd"] {
  background-color: #f83838 !important;
}

[class*="statusOffline"], .status-1fhblQ[class*="offline"] {
  background-color: #AAAAAA !important;
}

/* ========== 20. REACTIONS ========== */
[class*="reaction"], [class*="reactionInner"],
.reaction-1hd86g {
  background-color: rgba(14, 14, 15, 0.7) !important;
  border-color: rgba(58, 134, 255, 0.3) !important;
  transition: all 0.2s ease;
}

[class*="reaction"]:hover {
  background-color: rgba(58, 134, 255, 0.2) !important;
  border-color: var(--luffy-blue) !important;
}

/* ========== 21. EMBEDS & ATTACHMENTS ========== */
[class*="embed"], [class*="attachment"], [class*="messageAttachment"],
.embed-IeVjo6, .attachment-33OFj0 {
  background-color: var(--luffy-glass) !important;
  border-left: 4px solid var(--luffy-blue) !important;
  border-radius: 8px;
  backdrop-filter: blur(6px);
}

[class*="embedTitle"], [class*="embedAuthor"] {
  color: var(--luffy-blue) !important;
}

/* ========== 22. CONTEXT MENUS ========== */
[class*="contextMenu"], [class*="menu"],
.contextMenu-2QQOoN {
  background-color: var(--luffy-glass-light) !important;
  backdrop-filter: blur(10px);
  border: 1px solid rgba(58, 134, 255, 0.3);
  border-radius: 8px;
}

[class*="contextMenu"] [class*="item"]:hover,
[class*="menu"] [class*="item"]:hover {
  background-color: rgba(58, 134, 255, 0.2) !important;
}

[class*="contextMenu"] [class*="dangerItem"]:hover {
  background-color: rgba(248, 56, 56, 0.2) !important;
}

/* ========== 23. VOICE CHANNELS ========== */
[class*="voiceUser"], [class*="voiceChannel"],
.voiceUser-1mUZjI {
  background-color: rgba(14, 14, 15, 0.6) !important;
  transition: all 0.2s ease;
}

[class*="voiceUser"]:hover, [class*="voiceChannel"]:hover {
  background-color: rgba(58, 134, 255, 0.15) !important;
}

/* ========== 24. BADGES & UNREAD ========== */
[class*="badge"], [class*="unread"], [class*="mentionBadge"],
.badge-1hSds3, .unread-3zKbIZ {
  background-color: var(--luffy-blue) !important;
  color: #FFFFFF !important;
  font-weight: 700;
}

/* ========== 25. SEARCH BAR ========== */
[class*="searchBar"], [class*="search"],
.search-1sPmQm {
  background-color: var(--luffy-glass) !important;
  border: 1px solid rgba(58, 134, 255, 0.4) !important;
  border-radius: 8px;
}

[class*="searchBar"]:focus-within {
  border-color: var(--luffy-blue) !important;
  box-shadow: 0 0 8px rgba(58, 134, 255, 0.3);
}

/* ========== 26. SETTINGS & MODALS ========== */
[class*="standardSidebarView"], [class*="settingsTab"],
.standardSidebarView-3F1I7i, .settingsTab-OK3ohe {
  background-color: transparent !important;
}

[class*="settingsTab"]:hover {
  background-color: rgba(58, 134, 255, 0.15) !important;
}

[class*="settingsTab"][class*="selected"], [class*="settingsTab"][class*="active"] {
  background-color: var(--luffy-blue) !important;
  color: #FFFFFF !important;
}

/* ========== 27. NOTIFICATIONS & TOASTS ========== */
[class*="notification"], [class*="toast"], [class*="snackbar"],
.notification-1Uh6f5, .toast-2aSIJ- {
  background-color: var(--luffy-glass-light) !important;
  border-left: 4px solid var(--luffy-blue);
  backdrop-filter: blur(8px);
  border-radius: 8px;
}

/* ========== 28. SPOILER TAGS ========== */
[class*="spoilerHidden"], [class*="spoilerRevealed"],
.spoilerText-3p6IlD {
  background-color: var(--luffy-glass) !important;
  border-radius: 4px;
}

[class*="spoilerRevealed"] {
  background-color: rgba(40, 40, 45, 0.8) !important;
}

/* ========== 29. MESSAGE ACTIONS (reply, edit, etc) ========== */
[class*="messageActions"], [class*="messageToolbar"],
.messageActions-1hkIqK {
  background-color: transparent !important;
}

[class*="messageActions"] [class*="button"],
[class*="messageToolbar"] [class*="button"] {
  background-color: rgba(14, 14, 15, 0.7) !important;
  border-radius: 4px;
  transition: all 0.2s ease;
}

[class*="messageActions"] [class*="button"]:hover {
  background-color: var(--luffy-blue) !important;
  color: #FFFFFF !important;
}

/* ========== 30. DIVIDERS & SEPARATORS ========== */
[class*="divider"], [class*="separator"],
.divider-3573oO {
  background-color: rgba(255, 255, 255, 0.1) !important;
  border-color: rgba(255, 255, 255, 0.1) !important;
}

[class*="divider"] span {
  background-color: var(--luffy-glass) !important;
  color: var(--luffy-blue) !important;
}

/* ========== 31. LOADING SPINNERS ========== */
[class*="spinner"], [class*="loading"],
.spinner-1EHqDe {
  color: var(--luffy-blue) !important;
}

[class*="spinner"] circle {
  stroke: var(--luffy-blue) !important;
}

/* ========== 32. INVITE BUTTON ========== */
[class*="inviteButton"], [class*="invite"],
.inviteButton-1Ixwgf {
  background-color: var(--luffy-blue) !important;
  color: #FFFFFF !important;
  transition: all 0.2s ease;
}

[class*="inviteButton"]:hover {
  background-color: var(--luffy-blue-dark) !important;
  box-shadow: 0 4px 12px rgba(58, 134, 255, 0.4);
}

/* ========== 33. TYPING INDICATOR ========== */
[class*="typing"], [class*="typingDots"],
.typing-2J1mQg {
  color: var(--luffy-blue) !important;
}

[class*="typingDots"] {
  background-color: var(--luffy-blue) !important;
}

/* ========== 34. GAME ACTIVITY CARDS ========== */
[class*="gameActivity"], [class*="activity"],
.activity-2IXxXf {
  background-color: var(--luffy-glass) !important;
  border-left: 3px solid var(--luffy-blue);
  border-radius: 8px;
}

/* ========== 35. FORUM POSTS & TAGS ========== */
[class*="forumPost"], [class*="forumTag"],
[class*="tagBackground"] {
  background-color: var(--luffy-glass) !important;
  border-color: rgba(58, 134, 255, 0.3) !important;
}

/* ========== 36. GUILD ICONS & HOVER EFFECTS ========== */
[class*="guildIcon"], [class*="listItem"],
.guildIcon-CT-ZDq {
  transition: transform 0.2s ease, filter 0.2s ease;
}

[class*="guildIcon"]:hover, [class*="listItem"]:hover {
  transform: scale(1.08);
  filter: drop-shadow(0 0 8px rgba(58, 134, 255, 0.6));
}

/* ========== 37. AVATAR HOVER EFFECTS ========== */
[class*="avatar"], [class*="avatarContainer"],
.avatar-3EQepX {
  transition: filter 0.2s ease, transform 0.2s ease;
}

[class*="avatar"]:hover {
  filter: drop-shadow(0 0 8px rgba(58, 134, 255, 0.5));
  transform: scale(1.05);
}

/* ========== 38. ROLE PILLS ========== */
[class*="rolePill"], [class*="role"],
.rolePill-3c5Jv- {
  background-color: var(--luffy-glass) !important;
  border-color: var(--luffy-blue) !important;
  color: var(--luffy-text) !important;
}

/* ========== 39. VOICE STATE & CONTROLS ========== */
[class*="voiceState"], [class*="voiceButton"],
.voiceState-IlD46c {
  transition: all 0.2s ease;
}

[class*="voiceState"] [class*="button"]:hover,
[class*="voiceButton"]:hover {
  color: var(--luffy-blue) !important;
  background-color: rgba(58, 134, 255, 0.15) !important;
}

/* ========== 40. FINAL SAFETY OVERRIDES ========== */
/* Ensure no invisible text */
* {
  opacity: 1 !important;
}

/* Prevent accidental white-on-white */
[style*="color: white"], [style*="color: #fff"], [style*="color: #FFFFFF"] {
  color: var(--luffy-text) !important;
}

/* Force all backgrounds to not be pure white */
[style*="background: white"], [style*="background: #fff"], [style*="background: #FFFFFF"] {
  background-color: var(--luffy-glass) !important;
}

/* ========== 41. EXTRA: SMOOTH TRANSITIONS ========== */
button, a, input, textarea, [role="button"], [role="link"] {
  transition: all 0.15s cubic-bezier(0.4, 0, 0.2, 1);
}

/* ========== 42. EXTRA: FOCUS STATES ========== */
*:focus, *:focus-visible {
  outline: 2px solid rgba(58, 134, 255, 0.5) !important;
  outline-offset: 2px;
}

/* ========== 43. EXTRA: ACTIVE STATES ========== */
[class*="active"], [class*="selected"], [class*="focused"] {
  background-color: rgba(58, 134, 255, 0.15) !important;
  border-color: var(--luffy-blue) !important;
}

/* ========== 44. EXTRA: DISABLED STATES ========== */
[disabled], [class*="disabled"] {
  opacity: 0.5 !important;
  cursor: not-allowed !important;
}

/* ========== 45. EXTRA: CHAT INPUT CONTAINER ========== */
[class*="channelTextArea"], [class*="textAreaContainer"],
.channelTextArea-rNsIhG {
  background-color: transparent !important;
  border: none !important;
}

/* ========== 46. EXTRA: ENSURE CHAT STAYS TRANSPARENT ========== */
[class*="chat"] [class*="background"],
[class*="messages"] [class*="background"],
[class*="scroller"] [class*="background"],
[class*="messagesWrapper"] [class*="background"] {
  background-color: transparent !important;
  background-image: none !important;
}

/* ========== 47. EXTRA: THREAD STYLING ========== */
[class*="thread"], [class*="threadContainer"],
.thread-1qXc9e {
  background-color: transparent !important;
}

[class*="threadSpine"] {
  background-color: var(--luffy-blue) !important;
}

/* ========== 48. EXTRA: CALL CONTAINER ========== */
[class*="callContainer"], [class*="voiceContainer"],
.callContainer-HtHEWV {
  background-color: var(--luffy-glass-light) !important;
  backdrop-filter: blur(10px);
}

[class*="callContainer"] [class*="button"]:hover {
  background-color: var(--luffy-blue) !important;
}

/* ========== 49. EXTRA: DISCOVERY SECTIONS ========== */
[class*="guildsDiscovery"], [class*="shop"], [class*="discovery"],
.guildsDiscovery-Qf7EFe {
  background-color: var(--luffy-glass) !important;
  backdrop-filter: blur(8px);
}

/* ========== 50. EXTRA: FINAL PERFECTION ========== */
/* Ensure all text is readable */
[class*="text"] {
  text-shadow: 0 1px 2px rgba(0, 0, 0, 0.3);
}

/* Ensure all buttons have proper contrast */
[class*="button"] {
  font-weight: 600;
}

/* Smooth animations */
* {
  animation-duration: 0.3s !important;
}
